const PROCESSING_FEE = 5;

const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
};

type Item = { type: string };
type Step = { op: "quote"; items: Item[] };
type Scenario = { customer: unknown; steps: Step[] };

const basePremiumForItem = (item: Item): number =>
  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;

const quoteStep = (step: Step): { premium: number } => ({
  premium:
    step.items.reduce((sum, item) => sum + basePremiumForItem(item), 0) +
    PROCESSING_FEE,
});

export const runScenario = (scenario: Scenario): { results: unknown[] } => ({
  results: scenario.steps.map(quoteStep),
});

