import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote — empty + base premiums per item type
  it("empty item list → premium 5 G (processing fee only)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result.results[0]).toEqual({ premium: 5 });
  });
  it("single sword → premium 105 G (100 base + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 105 });
  });
  it("single amulet → premium 65 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 65 });
  });
  it("single staff → premium 85 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "staff", material: "wood", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 85 });
  });
  it("single potion → premium 45 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 45 });
  });

  // Multiple items / components
  it.todo("two swords → premium 205 G (200 base + 5 fee)");
  it.todo("2 runes → premium 55 G (50 base + 5 fee)");
  it.todo("3 runes block → premium 65 G (60 base + 5 fee)");
  it.todo("4 runes no block → premium 105 G (100 base + 5 fee)");
  it.todo("7 runes → premium 180 G (175 base + 5 fee)");
  it.todo("2 runes + 1 moonstone no block → premium 80 G");
  it.todo("3 runes + 3 moonstones two blocks → premium 125 G");

  // Item-specific modifiers
  it.todo("cursed sword newcomer → premium 165 G");
  it.todo("high enchantment (≥5) sword → premium 135 G (100 + 30 + 5)");
  it.todo("cursed + high enchantment sword → premium 185 G (100 + 50 + 30 + 5)");
  it.todo("policy with cursed sword + plain amulet → premium 215 G (160 + 50 + 5)");

  // Policy-wide modifiers
  it.todo("loyal customer (≥2 years) sword → premium 85 G (100 − 20 + 5)");
  it.todo("first insurance surcharge sword first quote → premium 115 G (100 + 10 + 5)");
  it.todo("second quote contract gets 15% follow-up discount → premium 100 G (100 + 10 − 15 + 5)");

  // Integration example
  it.todo("long-standing customer's second contract cursed sword enchantment 7 → premium 160 G");

  // Rounding
  it.todo("rounds premium up in MHPCO's favor (197.5 → 198)");

  // Claim — basic
  it.todo("standard sword damage 500 → payout 400 (full minus 100 deductible)");
  it.todo("rune damage 200 → payout 100");
  it.todo("high enchantment (≥8) sword damage 1000 → payout 400 (50% then deductible)");
  it.todo("dragon material sword damage 800 → payout 700 (full then deductible)");
  it.todo("dragon material + enchantment 9 sword damage 1000 → payout 400 (50% wins)");
  it.todo("multiple damages each get own deductible (sword 500 + amulet 300 → 600)");
  it.todo("cap exhaustion: two successive claims of 1500 each on sword (1000/2000 cap) → 1400 then 600");
  it.todo("rounds payout down in MHPCO's favor (350.5 → 350)");

  // Error cases
  it.todo("quote with unknown item type → throws error");
  it.todo("claim referencing item not in policy → throws error");
  it.todo("claim with negative damage amount → throws error");
  it.todo("claim with more damages of a type than policy covers → throws error");
});

