        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 135 });
  });
  it("cursed + high enchantment sword → premium 185 G (100 + 50 + 30 + 5)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 5, cursed: true }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 185 });
  });
  it.todo("policy with cursed sword + plain amulet → premium 215 G (160 + 50 + 5)");

  // Policy-wide modifiers
  it.todo("loyal customer (≥2 years) sword → premium 85 G (100 − 20 + 5)");
  it.todo("first insurance surcharge sword first quote → premium 115 G (100 + 10 + 5)");
  it.todo("second quote contract gets 15% follow-up discount → premium 100 G (100 + 10 − 15 + 5)");

  // Integration example
  it.todo("long-standing customer's second contract cursed sword enchantment 7 → premium 160 G");

  // Rounding
  it.todo("rounds premium up in MHPCO's favor (197.5 → 198)");

  // Claim — basic
  it.todo("standard sword damage 500 → payout 400 (full minus 100 deductible)");
  it.todo("rune damage 200 → payout 100");
  it.todo("high enchantment (≥8) sword damage 1000 → payout 400 (50% then deductible)");
  it.todo("dragon material sword damage 800 → payout 700 (full then deductible)");
  it.todo("dragon material + enchantment 9 sword damage 1000 → payout 400 (50% wins)");
  it.todo("multiple damages each get own deductible (sword 500 + amulet 300 → 600)");
  it.todo("cap exhaustion: two successive claims of 1500 each on sword (1000/2000 cap) → 1400 then 600");
  it.todo("rounds payout down in MHPCO's favor (350.5 → 350)");

  // Error cases
  it.todo("quote with unknown item type → throws error");
  it.todo("claim referencing item not in policy → throws error");
  it.todo("claim with negative damage amount → throws error");
  it.todo("claim with more damages of a type than policy covers → throws error");
});

const PROCESSING_FEE = 5;
const COMPONENT_BASE_PREMIUM = 25;
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;
const CURSE_SURCHARGE_RATE = 0.5;
const FIRST_INSURANCE_RATE = 0.1;
const HIGH_ENCHANTMENT_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;

const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

type Item = {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};
type Step = { op: "quote"; items: Item[] };
type Scenario = { customer: unknown; steps: Step[] };

const componentGroupPremium = (count: number): number =>
  count === COMPONENT_BLOCK_SIZE
    ? COMPONENT_BLOCK_PREMIUM
    : count * COMPONENT_BASE_PREMIUM;

const isMainItem = ({ type }: Item): boolean => type in BASE_PREMIUM_BY_TYPE;

const mainItemPremium = (item: Item): number => {
  const base = BASE_PREMIUM_BY_TYPE[item.type];
  const cursedRate = item.cursed ? CURSE_SURCHARGE_RATE + FIRST_INSURANCE_RATE : 0;
  const highEnchantRate =
    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? HIGH_ENCHANTMENT_RATE : 0;
  return base * (1 + cursedRate + highEnchantRate);
};

const countByType = (items: Item[]): Map<string, number> =>
  items.reduce(
    (counts, { type }) => counts.set(type, (counts.get(type) ?? 0) + 1),
    new Map<string, number>(),
  );

const sumComponentPremiums = (components: Item[]): number =>
  [...countByType(components).values()]
    .reduce((sum, count) => sum + componentGroupPremium(count), 0);

const sumItemPremiums = (items: Item[]): number => {
  const mains = items.filter(isMainItem);
  const components = items.filter((i) => !isMainItem(i));
  const mainsSum = mains.reduce((sum, item) => sum + mainItemPremium(item), 0);
  return mainsSum + sumComponentPremiums(components);
};

const quotePremiumFor = (step: Step): { premium: number } => ({
  premium: sumItemPremiums(step.items) + PROCESSING_FEE,
});

export const runScenario = (scenario: Scenario): { results: unknown[] } => ({
  results: scenario.steps.map(quotePremiumFor),
});

