2. Key Technical Concepts:
   - TDD red-green-refactor (autonomous, no human gates)
   - TypeScript with Vitest test framework
   - Skill-based phase invocations
   - APP (Absolute Priority Premise) mass calculation
   - Discriminated union types
   - Premium calculation: base premiums per type, component blocks of 3 alike (60G), modifiers (curse 50%, high-enchant 30%, loyalty 20% off, first-insurance 10%, follow-up 15% off), processing fee 5G
   - Additive (not multiplicative) modifier stacking
   - Claim processing: deductible 100G per damage, payout cap 2× insurance sum, enchantment ≥8 → 50% reimbursement, dragon material → 100% reimbursement
   - Rounding in MHPCO's favor (ceil for premium, floor for payout)

3. Files and Code Sections:
   - `src/claim-office.spec.ts` — 33 tests, currently 25 passing, 8 todos
   - `src/claim-office.ts` — Current implementation includes:
     ```typescript
     const PROCESSING_FEE = 5;
     const COMPONENT_BASE_PREMIUM = 25;
     const COMPONENT_BLOCK_SIZE = 3;
     const COMPONENT_BLOCK_PREMIUM = 60;
     const COMPONENT_INSURANCE_VALUE = 250;
     const CURSE_SURCHARGE_RATE = 0.5;
     const FIRST_INSURANCE_RATE = 0.1;
     const HIGH_ENCHANTMENT_RATE = 0.3;
     const HIGH_ENCHANTMENT_THRESHOLD = 5;
     const LOYALTY_DISCOUNT_RATE = 0.2;
     const LOYALTY_YEARS_THRESHOLD = 2;
     const FOLLOWUP_DISCOUNT_RATE = 0.15;
     const DEDUCTIBLE = 100;
     const CAP_MULTIPLIER = 2;
     const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
     const HALF_PAYOUT_RATE = 0.5;

     const BASE_PREMIUM_BY_TYPE: Record<string, number> = { sword: 100, amulet: 60, staff: 80, potion: 40 };
     const INSURANCE_VALUE_BY_TYPE: Record<string, number> = { sword: 1000, amulet: 600, staff: 800, potion: 400 };

     type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean; };
     type Damage = { itemType: string; amount: number };
     type Incident = { cause: string; damages: Damage[] };
     type QuoteStep = { op: "quote"; items: Item[] };
     type ClaimStep = { op: "claim"; policy: number; incident: Incident };
     type Step = QuoteStep | ClaimStep;
     type Customer = { yearsWithMHPCO: number; firstQuote?: boolean };
     type Scenario = { customer: Customer; steps: Step[] };

     // Helpers: componentGroupPremium, isMainItem, isHighEnchantment, qualifiesForFirstInsurance,
     // surchargeRates, mainItemPremium, countByType, sumComponentPremiums, partitionItems, sumItemPremiums
     // customerRateAdjustments, policyWideRate, ceilInFavor, quotePremiumFor
     // itemInsuranceValue, policyInsuranceSum, findPolicyItem, halvesPayout, damagePayout, claimResult
     // runStep, runScenario

     const findPolicyItem = (policyItems: Item[], itemType: string): Item | undefined =>
       policyItems.find((item) => item.type === itemType);

     const halvesPayout = (item: Item | undefined): boolean =>
       (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD;

     const damagePayout = (damage: Damage, policyItems: Item[]): number => {
       const policyItem = findPolicyItem(policyItems, damage.itemType);
       const reimbursed = halvesPayout(policyItem) ? damage.amount * HALF_PAYOUT_RATE : damage.amount;
       return Math.max(0, reimbursed - DEDUCTIBLE);
     };

     const claimResult = (step: ClaimStep, policyItems: Item[]): { payout: number; remainingCap: number } => {
       const insuranceSum = policyInsuranceSum(policyItems);
       const cap = insuranceSum * CAP_MULTIPLIER;
       const payout = step.incident.damages.reduce((sum, d) => sum + damagePayout(d, policyItems), 0);
       return { payout, remainingCap: cap - payout };
     };

     const runStep = (step: Step, index: number, scenario: Scenario): unknown =>
       step.op === "quote"
         ? quotePremiumFor(step, scenario.customer, index > 0)
         : claimResult(step, (scenario.steps[step.policy] as QuoteStep).items);

     export const runScenario = (scenario: Scenario): { results: unknown[] } => ({
       results: scenario.steps.map((step, i) => runStep(step, i, scenario)),
     });
     ```
